const sumBasePremiums = (items: Item[]): number =>
  items.reduce((total, item) => total + BASE_PREMIUM[item.type], 0);

type Modifier = {
  rate: number;
  baseFor: (items: Item[], policyBase: number) => number;
  applies: (customer: Customer) => boolean;
};

const ALWAYS = (): boolean => true;
const itemsMatching = (predicate: (item: Item) => boolean) =>
  (items: Item[]): number => sumBasePremiums(items.filter(predicate));
const wholePolicy = (_items: Item[], policyBase: number): number => policyBase;

const MODIFIERS: Modifier[] = [
  { rate: CURSE_SURCHARGE,            baseFor: itemsMatching(isCursed),          applies: ALWAYS },
