  { rate: -LOYALTY_DISCOUNT,          baseFor: wholePolicy,                      applies: isLoyalCustomer },
];

const modifierDelta = (
  { rate, baseFor, applies }: Modifier,
  items: Item[],
  policyBase: number,
  customer: Customer,
