const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const surchargeOnMatching = (
  items: Item[],
  predicate: (item: Item) => boolean,
  rate: number,
): number =>
  items
    .filter(predicate)
    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);

const perItemSurcharges = (items: Item[]): number =>
  surchargeOnMatching(items, isCursed, CURSE_SURCHARGE)
  + surchargeOnMatching(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);

const policyWideAdjustments = (policyBase: number, customer: Customer): number => {
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  const loyalty = isLoyalCustomer(customer) ? -policyBase * LOYALTY_DISCOUNT : 0;
  return firstInsurance + loyalty;
};

const quotePremiumFor = (customer: Customer) =>
  ({ items }: QuoteStep): QuoteResult => {
    const policyBase = sumBasePremiumsByGroup(items);
    const total =
      policyBase
      + perItemSurcharges(items)
      + policyWideAdjustments(policyBase, customer)
      + PROCESSING_FEE;
    return { premium: Math.ceil(total) };
  };

